import { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { supabase } from '../supabase';
import {
    Trash2, Search, X, Folder, ArrowLeft,
    Edit2, Download, User, Star, PieChart, AlertTriangle, CheckCircle,
    Film, Smile, Meh, Frown,
    Calendar as CalendarIcon, Grid, Layers, CheckSquare, Square, ChevronLeft, ChevronRight, Tag
} from 'lucide-react';
import toast from 'react-hot-toast';
import { Skeleton } from './Skeleton';
import JSZip from 'jszip';
import { saveAs } from 'file-saver';

import { useStudents } from '../hooks/useStudents';
import { useTags } from '../hooks/useTags';
import { SchoolFilters } from './UI/SchoolFilters';
import { formatDate } from '../utils/formatters';
import { EvidenceService } from '../services/evidenceService';

export function EvidenceList() {
    const { students } = useStudents();
    const location = useLocation();
    const navigate = useNavigate();

    const initialStudentId = location.state?.studentId || '';

    const [evidences, setEvidences] = useState([]);
    const [studentsMap, setStudentsMap] = useState({});
    const [studentsList, setStudentsList] = useState([]);
    const [loading, setLoading] = useState(true);

    const [filterActivity, setFilterActivity] = useState(null);
    const [filterTag, setFilterTag] = useState('Todos');
    const [filterPeriod, setFilterPeriod] = useState('Todos'); 
    const [filterStudent, setFilterStudent] = useState(initialStudentId);
    const [filterPerformance, setFilterPerformance] = useState('Todos');
    const [searchTerm, setSearchTerm] = useState('');
    const [showStats, setShowStats] = useState(false);

    const [viewMode, setViewMode] = useState('grid');
    const [selectionMode, setSelectionMode] = useState(false);
    const [selectedIds, setSelectedIds] = useState([]);

    const [inspectorItem, setInspectorItem] = useState(null);
    const [isEditing, setIsEditing] = useState(false);
    const [isDownloading, setIsDownloading] = useState(false);
    const [editData, setEditData] = useState({ activityName: '', comment: '', studentIds: [], performance: '' });
    const [modalFilters, setModalFilters] = useState({ grade: 'Todos', section: 'Todos', level: 'Todos', shift: 'Todos' });

    const { availableTags } = useTags();

    // --- EFECTOS ---
    useEffect(() => {
        if (students.length > 0) {
            const map = {};
            const list = [];
            students.forEach(d => {
                map[d.id] = d.name;
                list.push({ id: d.id, name: d.name, grade: d.grade || '', section: d.section || '', level: d.level || '', shift: d.shift || '' });
            });
            setStudentsMap(map);
            setStudentsList(list.sort((a, b) => a.name.localeCompare(b.name)));
        }
    }, [students]);

    useEffect(() => {
        let subscription = null;

        const fetchEvidences = async (userId) => {
            try {
                const { data, error } = await supabase
                    .from('evidences')
                    .select('*, evidence_students(student_id)')
                    .eq('teacher_id', userId)
                    .order('capture_date', { ascending: false });

                if (error) throw error;

                const mappedEvs = data.map(doc => ({
                    id: doc.id,
                    teacherId: doc.teacher_id,
                    activityName: doc.activity_name,
                    comment: doc.comment,
                    fileUrl: doc.file_url,
                    fileType: doc.file_type,
                    isFavorite: doc.is_favorite,
                    date: { seconds: new Date(doc.capture_date).getTime() / 1000 },
                    captureDate: doc.capture_date,
                    performance: doc.performance,
                    period: doc.period,
                    tags: doc.tags || [],
                    studentIds: (doc.evidence_students || []).map(m => m.student_id)
                }));

                mappedEvs.sort((a, b) => {
                    if (a.isFavorite && !b.isFavorite) return -1;
                    if (!a.isFavorite && b.isFavorite) return 1;
                    return new Date(b.captureDate).getTime() - new Date(a.captureDate).getTime();
                });

                setEvidences(mappedEvs);
                setLoading(false);
            } catch (err) {
                console.error("Error fetching evidences", err);
                setLoading(false);
            }
        };

        const { data: authListener } = supabase.auth.onAuthStateChange((event, session) => {
            if (session?.user) {
                fetchEvidences(session.user.id);
                subscription = supabase.channel('evidences_channel')
                    .on('postgres_changes', { event: '*', schema: 'public', table: 'evidences', filter: `teacher_id=eq.${session.user.id}` }, payload => {
                        fetchEvidences(session.user.id);
                    })
                    .subscribe();
            } else {
                setEvidences([]);
                setLoading(false);
                if (subscription) supabase.removeChannel(subscription);
            }
        });

        return () => {
             authListener?.subscription.unsubscribe();
             if (subscription) supabase.removeChannel(subscription);
        };
    }, []);

    // --- HELPERS ---
    const getMissingStudents = () => {
        if (studentsList.length === 0) return [];
        const seenIds = new Set();
        evidences.forEach(ev => { if (ev.studentIds && Array.isArray(ev.studentIds)) ev.studentIds.forEach(id => seenIds.add(id)); });
        return studentsList.filter(s => !seenIds.has(s.id));
    };
    const missingStudents = getMissingStudents();
    const coveragePercent = studentsList.length > 0 ? Math.round(((studentsList.length - missingStudents.length) / studentsList.length) * 100) : 0;

    const getFilteredEvidences = () => {
        return evidences.filter(item => {
            const matchesText = item.activityName?.toLowerCase().includes(searchTerm.toLowerCase()) || (item.comment && item.comment.toLowerCase().includes(searchTerm.toLowerCase()));
            const matchesActivity = filterActivity ? item.activityName === filterActivity : true;
            const matchesTag = filterTag === 'Todos' || (item.tags && item.tags.includes(filterTag));
            const matchesPeriod = filterPeriod === 'Todos' || item.period === filterPeriod;
            const matchesStudent = filterStudent ? (item.studentIds && item.studentIds.includes(filterStudent)) : true;
            const matchesPerformance = filterPerformance === 'Todos' || item.performance === filterPerformance;
            return matchesText && matchesActivity && matchesStudent && matchesPerformance && matchesTag && matchesPeriod;
        });
    };
    const filteredItems = getFilteredEvidences();

    const folders = {};
    if (!filterStudent && filterPerformance === 'Todos' && viewMode === 'grid') {
        filteredItems.forEach(item => {
            const name = item.activityName || "Sin Nombre";
            if (!folders[name]) folders[name] = [];
            folders[name].push(item);
        });
    }

    const getStudentsForEdit = () => {
        return studentsList.filter(s => {
            const matchGrade = modalFilters.grade === 'Todos' || s.grade === modalFilters.grade;
            const matchSection = modalFilters.section === 'Todos' || s.section === modalFilters.section;
            const matchLevel = modalFilters.level === 'Todos' || s.level === modalFilters.level;
            const matchShift = modalFilters.shift === 'Todos' || s.shift === modalFilters.shift;
            return matchGrade && matchSection && matchLevel && matchShift;
        });
    };

    const getPerformanceIcon = (perf) => {
        switch (perf) {
            case 'logrado': return <Smile size={16} color="#10b981" fill="#ecfdf5" />;
            case 'proceso': return <Meh size={16} color="#f59e0b" fill="#fffbeb" />;
            case 'apoyo': return <Frown size={16} color="#ef4444" fill="#fef2f2" />;
            default: return null;
        }
    };
    const getPerformanceColor = (perf) => {
        switch (perf) {
            case 'logrado': return '#10b981';
            case 'proceso': return '#f59e0b';
            case 'apoyo': return '#ef4444';
            default: return '#e5e7eb';
        }
    };

    // --- CALENDAR HELPERS ---
    const groupEvidencesByDate = (items) => {
        const groups = {};
        items.forEach(item => {
            const date = item.date ? new Date(item.date.seconds * 1000) : new Date();
            const today = new Date();
            const yesterday = new Date(); yesterday.setDate(yesterday.getDate() - 1);

            let key = date.toLocaleDateString();
            if (date.toDateString() === today.toDateString()) key = 'Hoy';
            else if (date.toDateString() === yesterday.toDateString()) key = 'Ayer';

            if (!groups[key]) groups[key] = [];
            groups[key].push(item);
        });
        return groups;
    };

    // --- ACCIONES ---
    const handleDelete = async () => {
        if (!confirm("¿Borrar esta evidencia definitivamente?")) return;
        try {
            await EvidenceService.delete(inspectorItem.id, inspectorItem.fileUrl);
            setInspectorItem(null);
            toast.success("Evidencia eliminada");
        } catch (error) { toast.error("Error borrando"); }
    };

    const toggleFavorite = async (item, e) => {
        e?.stopPropagation();
        try {
            await EvidenceService.toggleFavorite(item.id, item.isFavorite);
            if (inspectorItem?.id === item.id) setInspectorItem(prev => ({ ...prev, isFavorite: !prev.isFavorite }));
            toast.success(item.isFavorite ? "Quitado de favoritos" : "Agregado a favoritos ⭐", { duration: 1000 });
        } catch (e) { console.error(e); }
    };

    const handleUpdate = async () => {
        const toastId = toast.loading("Guardando cambios...");
        try {
            await EvidenceService.update(inspectorItem.id, {
                activityName: editData.activityName, comment: editData.comment,
                studentIds: editData.studentIds, performance: editData.performance
            });
            setInspectorItem(prev => ({ ...prev, ...editData }));
            setIsEditing(false);
            toast.success("Actualizado", { id: toastId });
        } catch (e) { toast.error("Error al guardar", { id: toastId }); }
    };

    const downloadFolderZip = async () => {
        const itemsToDownload = selectionMode && selectedIds.length > 0
            ? filteredItems.filter(i => selectedIds.includes(i.id))
            : filteredItems;

        if (itemsToDownload.length === 0) return;

        setIsDownloading(true);
        const toastId = toast.loading(`Empaquetando ${itemsToDownload.length} archivos...`);
        const zip = new JSZip();
        try {
            const promises = itemsToDownload.map(async (item, index) => {
                const response = await fetch(item.fileUrl);
                const blob = await response.blob();
                const ext = item.fileUrl.includes('.mp4') ? 'mp4' : 'jpg';
                const fileName = `${index + 1}_${item.activityName}.${ext} `;
                zip.file(fileName, blob);
            });
            await Promise.all(promises);
            const content = await zip.generateAsync({ type: "blob" });
            const zipName = filterActivity ? `${filterActivity}.zip` : `Evidencias.zip`;
            saveAs(content, zipName);
            toast.success("¡Descarga lista!", { id: toastId });
            if (selectionMode) { setSelectionMode(false); setSelectedIds([]); }
        } catch (error) { console.error(error); toast.error("Error descarga.", { id: toastId }); } finally { setIsDownloading(false); }
    };

    // --- BULK ACTIONS ---
    const toggleSelection = (id) => {
        setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    };

    const handleBulkDelete = async () => {
        if (!confirm(`¿Borrar ${selectedIds.length} evidencias seleccionadas ? `)) return;
        const toastId = toast.loading("Borrando...");
        try {
            const itemsToDelete = evidences.filter(e => selectedIds.includes(e.id));
            await Promise.all(itemsToDelete.map(item => EvidenceService.delete(item.id, item.fileUrl)));
            setSelectedIds([]);
            setSelectionMode(false);
            toast.success("Evidencias eliminadas", { id: toastId });
        } catch (e) { toast.error("Error borrando", { id: toastId }); }
    };

    // --- SLIDESHOW ---
    const handleNext = (e) => {
        e.stopPropagation();
        const currentIndex = filteredItems.findIndex(i => i.id === inspectorItem.id);
        if (currentIndex < filteredItems.length - 1) setInspectorItem(filteredItems[currentIndex + 1]);
    };

    const handlePrev = (e) => {
        e.stopPropagation();
        const currentIndex = filteredItems.findIndex(i => i.id === inspectorItem.id);
        if (currentIndex > 0) setInspectorItem(filteredItems[currentIndex - 1]);
    };

    if (loading) return <div style={{ paddingBottom: '20px' }}><Skeleton height="50px" style={{ marginBottom: '10px' }} /><Skeleton height="200px" /></div>;

    // --- STYLES ---
    const containerStyle = { paddingBottom: '20px' };
    const toolbarStyle = { background: 'var(--bg-card)', padding: '10px', borderRadius: '12px', marginBottom: '15px', border: '1px solid var(--border-color)', display: 'flex', flexDirection: 'column', gap: '10px' };
    const inputContainerStyle = { position: 'relative', flex: 1 };
    const searchIconStyle = { position: 'absolute', left: '10px', top: '10px', color: 'var(--text-secondary)' };
    const inputStyle = { width: '100%', padding: '8px 8px 8px 32px', borderRadius: '8px', border: '1px solid var(--border-color)', fontSize: '13px', background: 'var(--bg-primary)', color: 'var(--text-primary)' };
    const selectStyle = { maxWidth: '120px', padding: '8px', borderRadius: '8px', border: '1px solid var(--border-color)', fontSize: '12px', background: filterStudent ? 'var(--accent-color)' : 'var(--bg-primary)', color: filterStudent ? 'white' : 'var(--text-primary)' };

    return (
        <div style={containerStyle}>

            {/* TOOLBAR */}
            <div style={toolbarStyle}>
                <div style={{ display: 'flex', gap: '10px' }}>
                    <div style={inputContainerStyle}>
                        <Search size={16} style={searchIconStyle} />
                        <input placeholder="Buscar..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} style={inputStyle} />
                    </div>
                    <select value={filterStudent} onChange={e => { setFilterStudent(e.target.value); setFilterActivity(null); }} style={selectStyle}>
                        <option value="" style={{ color: 'black' }}>👤 Portafolio...</option>
                        {studentsList.map(s => <option key={s.id} value={s.id} style={{ color: 'black' }}>{s.name}</option>)}
                    </select>
                </div>

                <div style={{ display: 'flex', justify-content: 'space-between', alignItems: 'center' }}>
                    <div style={{ display: 'flex', gap: '5px' }}>
                        <select value={filterTag} onChange={e => setFilterTag(e.target.value)} style={{ padding: '6px', borderRadius: '8px', border: '1px solid var(--border-color)', fontSize: '11px', background: 'var(--bg-primary)', color: 'var(--text-primary)', maxWidth: '100px' }}>
                            <option value="Todos">🏷️ Etiquetas</option>
                            {availableTags.map(t => <option key={t} value={t}>{t}</option>)}
                        </select>
                        <select value={filterPeriod} onChange={e => setFilterPeriod(e.target.value)} style={{ padding: '6px', borderRadius: '8px', border: '1px solid var(--border-color)', fontSize: '11px', background: 'var(--bg-primary)', color: 'var(--text-primary)', maxWidth: '100px' }}>
                            <option value="Todos">📅 Periodo</option>
                            <option value="P1">Periodo 1</option>
                            <option value="P2">Periodo 2</option>
                            <option value="P3">Periodo 3</option>
                            <option value="P4">Periodo 4</option>
                        </select>
                        <select value={filterPerformance} onChange={e => setFilterPerformance(e.target.value)} style={{ padding: '6px', borderRadius: '8px', border: '1px solid var(--border-color)', fontSize: '11px', background: 'var(--bg-primary)', color: 'var(--text-primary)' }}>
                            <option value="Todos">🌈 Todos</option>
                            <option value="logrado">🟢 Logrado</option>
                            <option value="proceso">🟡 Proceso</option>
                            <option value="apoyo">🔴 Apoyo</option>
                        </select>

                        {/* VIEW MODE TOGGLE */}
                        <div style={{ display: 'flex', background: 'var(--bg-primary)', borderRadius: '8px', border: '1px solid var(--border-color)', padding: '2px' }}>
                            <button onClick={() => setViewMode('grid')} style={{ padding: '4px', borderRadius: '6px', border: 'none', background: viewMode === 'grid' ? 'var(--bg-card)' : 'transparent', color: viewMode === 'grid' ? 'var(--accent-color)' : 'var(--text-secondary)', cursor: 'pointer' }}><Grid size={14} /></button>
                            <button onClick={() => setViewMode('calendar')} style={{ padding: '4px', borderRadius: '6px', border: 'none', background: viewMode === 'calendar' ? 'var(--bg-card)' : 'transparent', color: viewMode === 'calendar' ? 'var(--accent-color)' : 'var(--text-secondary)', cursor: 'pointer' }}><CalendarIcon size={14} /></button>
                        </div>
                    </div>

                    <div style={{ display: 'flex', gap: '5px' }}>
                        {/* BULK ACTIONS TOGGLE */}
                        <button onClick={() => { setSelectionMode(!selectionMode); setSelectedIds([]); }} style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '11px', padding: '6px 10px', background: selectionMode ? 'var(--accent-color)' : 'var(--bg-primary)', color: selectionMode ? 'white' : 'var(--text-secondary)', border: '1px solid var(--border-color)', borderRadius: '20px', cursor: 'pointer' }}>
                            {selectionMode ? <CheckSquare size={12} /> : <Square size={12} />}
                        </button>

                        {selectionMode && selectedIds.length > 0 && (
                            <>
                                <button onClick={handleBulkDelete} style={{ padding: '6px', background: 'var(--danger-bg)', color: 'var(--danger-text)', border: '1px solid var(--danger-text)', borderRadius: '20px', cursor: 'pointer' }}><Trash2 size={12} /></button>
                                <button onClick={downloadFolderZip} style={{ padding: '6px', background: 'var(--success-bg)', color: 'var(--success-text)', border: '1px solid var(--success-text)', borderRadius: '20px', cursor: 'pointer' }}><Download size={12} /></button>
                            </>
                        )}

                        {!selectionMode && (filterActivity || filterStudent) && <button onClick={downloadFolderZip} disabled={isDownloading} style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '11px', padding: '6px 10px', background: 'var(--success-text)', color: 'white', border: 'none', borderRadius: '20px', cursor: 'pointer' }}><Download size={12} /> ZIP</button>}
                        <button onClick={() => setShowStats(!showStats)} style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '11px', padding: '6px 10px', background: showStats ? 'var(--warning-text)' : 'var(--bg-primary)', color: showStats ? 'white' : 'var(--text-secondary)', border: '1px solid var(--border-color)', borderRadius: '20px', cursor: 'pointer' }}><PieChart size={12} /></button>
                    </div>
                </div>

                <div style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '13px', fontWeight: 'bold', color: 'var(--text-primary)', marginTop: '5px' }}>
                    {filterStudent ? (<>👤 Portafolio: <span style={{ color: 'var(--accent-color)' }}>{studentsMap[filterStudent]}</span></>) : filterActivity ? (<><button onClick={() => setFilterActivity(null)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-primary)' }}><ArrowLeft size={14} /></button> 📂 {filterActivity}</>) : (<>📂 Todas las Carpetas</>)}
                </div>

                {showStats && (
                    <div style={{ marginTop: '5px', paddingTop: '10px', borderTop: '1px dashed var(--border-color)', animation: 'fadeIn 0.3s' }}>
                        <div style={{ display: 'flex', justify-content: 'space-between', alignItems: 'center', marginBottom: '5px' }}>
                            <span style={{ fontSize: '12px', fontWeight: 'bold', color: 'var(--text-secondary)' }}>Cobertura: {coveragePercent}%</span>
                            <span style={{ fontSize: '12px', color: 'var(--text-secondary)' }}>{studentsList.length - missingStudents.length}/{studentsList.length}</span>
                        </div>
                        <div style={{ width: '100%', height: '8px', background: 'var(--bg-primary)', borderRadius: '4px', overflow: 'hidden', marginBottom: '10px' }}>
                            <div style={{ width: `${coveragePercent}% `, height: '100%', background: coveragePercent === 100 ? 'var(--success-text)' : coveragePercent > 50 ? 'var(--warning-text)' : 'var(--danger-text)', transition: 'width 0.5s' }}></div>
                        </div>
                        {missingStudents.length > 0 && <div style={{ fontSize: '11px', color: 'var(--danger-text)' }}>Faltan: {missingStudents.slice(0, 5).map(s => s.name).join(', ')}{missingStudents.length > 5 && '...'}</div>}
                    </div>
                )}
            </div>

            {/* VISTA CARPETAS (Solo en Grid Mode y sin filtros activos) */}
            {!filterActivity && !filterStudent && filterPerformance === 'Todos' && viewMode === 'grid' && (
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                    {Object.keys(folders).map(name => (
                        <div key={name} onClick={() => setFilterActivity(name)} style={{ background: 'var(--bg-card)', borderRadius: '10px', border: '1px solid var(--border-color)', padding: '10px', display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer', boxShadow: '0 1px 2px rgba(0,0,0,0.05)' }}>
                            <Folder size={24} color="var(--accent-color)" fill="var(--bg-primary)" />
                            <div style={{ overflow: 'hidden' }}>
                                <div style={{ fontWeight: '600', fontSize: '13px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', color: 'var(--text-primary)' }}>{name}</div>
                                <div style={{ fontSize: '10px', color: 'var(--text-secondary)' }}>{folders[name].length} archivos</div>
                            </div>
                        </div>
                    ))}
                    {Object.keys(folders).length === 0 && filteredItems.length === 0 && <p style={{ gridColumn: 'span 2', textAlign: 'center', color: 'var(--text-secondary)' }}>No hay evidencias.</p>}
                </div>
            )}

            {/* VISTA GRID (Items individuales) */}
            {(filterActivity || filterStudent || filterPerformance !== 'Todos' || viewMode === 'grid') && viewMode === 'grid' && (filterActivity || filterStudent || filterPerformance !== 'Todos') && (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '2px' }}>
                    {filteredItems.map(item => (
                        <div key={item.id} onClick={() => {
                            if (selectionMode) toggleSelection(item.id);
                            else { setInspectorItem(item); setIsEditing(false); }
                        }} style={{ aspectRatio: '1/1', position: 'relative', overflow: 'hidden', background: 'var(--bg-primary)', borderBottom: `3px solid ${getPerformanceColor(item.performance)} `, cursor: 'pointer', opacity: selectionMode && !selectedIds.includes(item.id) ? 0.5 : 1 }}>
                            {(item.fileUrl.includes('.mp4') || item.fileType === 'video') && <Film size={16} color="white" style={{ position: 'absolute', top: 5, left: 5, zIndex: 2, dropShadow: '0 1px 2px rgba(0,0,0,0.5)' }} />}
                            {item.isFavorite && <Star size={16} color="#f59e0b" fill="#f59e0b" style={{ position: 'absolute', top: 5, right: 5, zIndex: 2, dropShadow: '0 1px 2px rgba(0,0,0,0.5)' }} />}
                            {selectionMode && selectedIds.includes(item.id) && <div style={{ position: 'absolute', inset: 0, background: 'rgba(59, 130, 246, 0.3)', zIndex: 10, display: 'flex', alignItems: 'center', justifyContent: 'center' }}><CheckCircle color="white" fill="#3b82f6" /></div>}
                            {item.performance && <div style={{ position: 'absolute', bottom: 5, right: 5, zIndex: 2, background: 'rgba(255,255,255,0.8)', borderRadius: '50%', padding: '2px' }}>{getPerformanceIcon(item.performance)}</div>}
                            {item.fileUrl.includes('.mp4') || item.fileType === 'video' ? (
                                <video src={item.fileUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                            ) : <img src={item.fileUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />}
                        </div>
                    ))}
                    {filteredItems.length === 0 && <p style={{ gridColumn: 'span 3', textAlign: 'center', padding: '20px', color: 'var(--text-secondary)' }}>No se encontraron fotos.</p>}
                </div>
            )}

            {/* VISTA CALENDARIO */}
            {viewMode === 'calendar' && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                    {Object.entries(groupEvidencesByDate(filteredItems)).map(([date, items]) => (
                        <div key={date}>
                            <div style={{ fontSize: '14px', fontWeight: 'bold', color: 'var(--text-primary)', marginBottom: '5px', paddingLeft: '5px', borderLeft: '3px solid var(--accent-color)' }}>{date}</div>
                            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '2px' }}>
                                {items.map(item => (
                                    <div key={item.id} onClick={() => {
                                        if (selectionMode) toggleSelection(item.id);
                                        else { setInspectorItem(item); setIsEditing(false); }
                                    }} style={{ aspectRatio: '1/1', position: 'relative', overflow: 'hidden', background: 'var(--bg-primary)', borderBottom: `3px solid ${getPerformanceColor(item.performance)} `, cursor: 'pointer', opacity: selectionMode && !selectedIds.includes(item.id) ? 0.5 : 1 }}>
