import { useState, useEffect } from 'react';
import { dbLocal, getPendingUploads, deletePendingUpload } from '../db';
import { supabase } from '../supabase';
import { RefreshCw, CloudOff, CheckCircle } from 'lucide-react';
import toast from 'react-hot-toast';

export function SyncStatus() {
  const [pendingCount, setPendingCount] = useState(0);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const updateCount = async () => {
        const count = await dbLocal.pendingUploads.count();
        setPendingCount(count);
    };

    const interval = setInterval(updateCount, 5000);
    updateCount();

    const handleOnline = () => { setIsOnline(true); syncNow(); };
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      clearInterval(interval);
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const syncNow = async () => {
    if (isSyncing || !navigator.onLine) return;

    const items = await getPendingUploads();
    if (items.length === 0) return;

    setIsSyncing(true);
    const toastId = toast.loading(`Sincronizando ${items.length} evidencias...`);

    const { data: { session } } = await supabase.auth.getSession();
    const userId = session?.user?.id || 'anon';

    try {
      let successCount = 0;

      for (const item of items) {
        try {
          // A. Subir Archivo a Storage
          const fileName = `${userId}/${item.timestamp}_${item.file.name}`;
          const { error: uploadError } = await supabase.storage.from('evidencias').upload(fileName, item.file);
          if (uploadError) throw uploadError;

          const { data: publicUrlData } = supabase.storage.from('evidencias').getPublicUrl(fileName);
          const downloadURL = publicUrlData.publicUrl;

          // B. Guardar en PostgreSQL
          const finalData = {
              teacher_id: userId,
              activity_name: item.metadata.activityName,
              comment: item.metadata.comment,
              performance: item.metadata.performance || null,
              file_url: downloadURL,
              file_type: item.file.type.startsWith('video/') ? 'video' : 'image',
              period: item.metadata.period,
              grade_tag: item.metadata.grade,
              section_tag: item.metadata.section,
              level_tag: item.metadata.level,
              tags: item.metadata.tags || [],
              capture_date: new Date(item.metadata.date || Date.now()).toISOString()
          };

          const { data: insertedEvidence, error: insertError } = await supabase
              .from('evidences')
              .insert(finalData)
              .select()
              .single();

          if (insertError) throw insertError;

          if (item.metadata.studentIds && item.metadata.studentIds.length > 0) {
              const mappings = item.metadata.studentIds.map(stId => ({
                  evidence_id: insertedEvidence.id,
                  student_id: stId
              }));
              await supabase.from('evidence_students').insert(mappings);
          }

          // C. Borrar de la cola local
          await deletePendingUpload(item.id);
          successCount++;

        } catch (err) {
          console.error("Error subiendo item:", err);
        }
      }

      if (successCount > 0) {
          toast.success(`¡${successCount} evidencias subidas!`, { id: toastId });
          setPendingCount(prev => prev - successCount);
      } else {
          toast.error("Error de sincronización", { id: toastId });
      }

    } catch (error) {
      console.error("Error crítico sync:", error);
    } finally {
      setIsSyncing(false);
    }
  };

  if (pendingCount === 0) return null;

  return (
    <div style={{
        marginBottom: '15px', padding: '10px', borderRadius: '8px',
        background: isOnline ? '#ecfdf5' : '#fff7ed',
        border: `1px solid ${isOnline ? '#10b981' : '#f97316'}`,
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        animation: 'fadeIn 0.5s'
    }}>
        <div style={{display:'flex', alignItems:'center', gap:'10px'}}>
            {isSyncing ? <RefreshCw className="spin" size={20} color="#10b981"/> : <CloudOff size={20} color="#f97316"/>}
            <div>
                <div style={{fontWeight:'bold', fontSize:'13px', color:'#333'}}>
                    {isSyncing ? 'Subiendo a la nube...' : 'Pendiente de subir'}
                </div>
                <div style={{fontSize:'11px', color:'#666'}}>
                    {pendingCount} archivos guardados en celular
                </div>
            </div>
        </div>

        {isOnline && !isSyncing && (
            <button onClick={syncNow} style={{background:'#10b981', color:'white', border:'none', padding:'5px 12px', borderRadius:'20px', fontSize:'11px', fontWeight:'bold', cursor:'pointer'}}>
                Subir
            </button>
        )}

        <style>{`.spin { animation: spin 1s linear infinite; } @keyframes spin { 100% { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

// src/context/AuthContext.jsx
import { createContext, useContext, useEffect, useState } from 'react';
import { supabase } from '../supabase';
import toast from 'react-hot-toast';

// 1. Crear el contexto (la "nube" de datos)
const AuthContext = createContext();

// 2. Hook personalizado para usarlo fácil
export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth debe usarse dentro de un AuthProvider');
  return context;
};

// 3. El Proveedor (El componente que envuelve la App)
export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  // Función Login (OAuth Google de Supabase)
  const login = async () => {
    try {
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        // Opcional: Para forzar la selección de cuenta
        options: {
          queryParams: {
            prompt: 'select_account',
          },
        },
      });
      if (error) throw error;
      // El toast quizás no se vea porque redirige inmediatamente.
    } catch (error) {
      console.error(error);
      toast.error('Error al iniciar sesión con Google');
    }
  };

  // Función Logout
  const logout = async () => {
    try {
      const { error } = await supabase.auth.signOut();
      if (error) throw error;
      toast.success('Sesión cerrada');
    } catch (error) {
      toast.error('Error al salir');
    }
  };

  // Escuchar cambios de sesión
  useEffect(() => {
    // Verificar sesión inicial
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
      setLoading(false);
    });

    // Escuchar cambios futuros
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
      setLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  return (
    <AuthContext.Provider value={{ user, login, logout, loading }}>
      {!loading && children}
    </AuthContext.Provider>
  );
}

