// src/hooks/useCamera.js
import { useState, useRef, useEffect } from 'react';
import toast from 'react-hot-toast';

export function useCamera() {
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [cameraStream, setCameraStream] = useState(null);
  const [facingMode, setFacingMode] = useState('environment');
  const [flashOn, setFlashOn] = useState(false);
  const [zoom, setZoom] = useState(1);
  const [zoomCap, setZoomCap] = useState(null); 

  const videoRef = useRef(null);

  // Conectar video al abrir
  useEffect(() => {
    if (isCameraOpen && videoRef.current && cameraStream) {
        videoRef.current.srcObject = cameraStream;
    }
  }, [isCameraOpen, cameraStream]);

  const startCamera = async (mode = 'photo') => {
    try {
      if (cameraStream) {
          cameraStream.getTracks().forEach(track => track.stop());
      }
      
      const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { 
              facingMode: facingMode, 
              width: { ideal: 1280 }, 
              height: { ideal: 720 } 
          },
          audio: mode === 'video'
      });

      setCameraStream(stream);
      setIsCameraOpen(true);

      const track = stream.getVideoTracks()[0];
      const capabilities = track.getCapabilities ? track.getCapabilities() : {};
      if (capabilities.zoom) setZoomCap(capabilities.zoom); else setZoomCap(null);

    } catch (err) {
      console.error(err);
      toast.error("No se pudo acceder a la cámara");
    }
  };

  const stopCamera = () => {
    if (cameraStream) {
        cameraStream.getTracks().forEach(track => track.stop());
    }
    setIsCameraOpen(false);
    setCameraStream(null);
  };

  const toggleFacingMode = () => {
      setFacingMode(prev => prev === 'environment' ? 'user' : 'environment');
  };

  // Reiniciar si cambia la cámara (frontal/trasera)
  useEffect(() => {
      if(isCameraOpen && !cameraStream) startCamera();
  }, [facingMode]);

  const handleZoom = (value) => {
      setZoom(value);
      if (cameraStream) {
          const track = cameraStream.getVideoTracks()[0];
          if (track.applyConstraints) track.applyConstraints({ advanced: [{ zoom: value }] }).catch(() => {});
      }
  };

  const toggleFlash = () => {
      if (!cameraStream) return;
      const track = cameraStream.getVideoTracks()[0];
      const newStatus = !flashOn;
      setFlashOn(newStatus);
      if (track.applyConstraints) track.applyConstraints({ advanced: [{ torch: newStatus }] }).catch(() => toast("Flash no disponible"));
  };

  return {
    isCameraOpen,
    cameraStream,
    videoRef,
    startCamera,
    stopCamera,
    toggleFacingMode,
    handleZoom,
    toggleFlash,
    zoom,
    zoomCap,
    flashOn,
    facingMode
  };
}

import { useState, useEffect } from 'react';
import { supabase } from '../supabase';
import toast from 'react-hot-toast';
import imageCompression from 'browser-image-compression';
import { saveOffline } from '../db';
import { EvidenceService } from '../services/evidenceService';
import { DEFAULT_FILTERS } from '../utils/constants';

export function useCaptureForm() {
  const [captureContext, setCaptureContext] = useState('class');
  const [activity, setActivity] = useState('');
  const [comment, setComment] = useState('');
  const [tags, setTags] = useState([]);
  const [performance, setPerformance] = useState('');
  const [customDate, setCustomDate] = useState(new Date().toISOString().split('T')[0]);
  const [files, setFiles] = useState([]);
  const [loading, setLoading] = useState(false);
  const [previewFile, setPreviewFile] = useState(null);

  const [allActivities, setAllActivities] = useState([]);
  const [suggestions, setSuggestions] = useState([]);
  const [recentActivities, setRecentActivities] = useState([]);
  const [keepData, setKeepData] = useState(false);

  const [selectedStudents, setSelectedStudents] = useState([]);

  // Filtros
  const [filters, setFilters] = useState(() => {
    const saved = localStorage.getItem('captureFilters');
    return saved ? JSON.parse(saved) : DEFAULT_FILTERS;
  });
  const [searchTerm, setSearchTerm] = useState('');

  // Periodo Académico
  const [currentPeriod, setCurrentPeriod] = useState('P1');

  // Carga de historial de actividades
  useEffect(() => {
    const { data: authListener } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session?.user) {
         // get history
         const { data: evs } = await supabase.from('evidences').select('activity_name').eq('teacher_id', session.user.id).order('capture_date', { ascending: false }).limit(100);
         if (evs) {
            const namesSet = new Set();
            evs.forEach(doc => { if(doc.activity_name) namesSet.add(doc.activity_name) });
            setAllActivities(Array.from(namesSet));
            setRecentActivities(Array.from(namesSet).slice(0, 5));
         }
      }
    });
    return () => authListener?.subscription.unsubscribe();
  }, []);

  useEffect(() => { localStorage.setItem('captureFilters', JSON.stringify(filters)); }, [filters]);

  const handleActivityChange = (e) => {
    const val = e.target.value;
    setActivity(val);
    if (val.length > 1) {
      const matches = allActivities.filter(a => a.toLowerCase().includes(val.toLowerCase()));
      setSuggestions(matches);
    } else { setSuggestions([]); }
  };

  const selectActivity = (name) => { setActivity(name); setSuggestions([]); };

  const toggleTag = (tag) => { if (tags.includes(tag)) setTags(prev => prev.filter(t => t !== tag)); else setTags(prev => [...prev, tag]); };

  const handleFilterChange = (field, value) => setFilters(prev => ({ ...prev, [field]: value }));

  const handleFilesChange = (e) => {
    const selectedFiles = Array.from(e.target.files);
    if (selectedFiles.length === 0) return;
    const validFiles = [];
    const MAX_VIDEO_SIZE = 50 * 1024 * 1024;
    selectedFiles.forEach(file => {
      if (file.type.startsWith('video/') && file.size > MAX_VIDEO_SIZE) toast.error(`Video pesado ignorado.`);
      else validFiles.push(file);
    });
    setFiles(prev => [...prev, ...validFiles]);
    e.target.value = "";
  };

  const removeFile = (index) => setFiles(prev => prev.filter((_, i) => i !== index));

  const saveEvidence = async (e) => {
    e.preventDefault();
    if (files.length === 0 || !activity) return toast.error("Falta foto/video o actividad");
    setLoading(true);
    const loadingToast = toast.loading(`Subiendo ${files.length} archivos...`);

    // get user id
    const { data: { session } } = await supabase.auth.getSession();
    if(!session?.user) {
        toast.error("Unauthenticated");
        setLoading(false);
        return;
    }

    try {
      const now = new Date();
      const [year, month, day] = customDate.split('-').map(Number);
      const finalDate = new Date(year, month - 1, day, now.getHours(), now.getMinutes());

      let count = 0;
      for (const file of files) {
        count++;
        let fileToUpload = file;
        if (file.type.startsWith('image/')) {
          try { fileToUpload = await imageCompression(file, { maxSizeMB: 0.5, maxWidthOrHeight: 1280, useWebWorker: true }); }
          catch (error) { console.error(error); }
        }

        const isSchoolMode = captureContext === 'school';

        const docData = {
          activityName: activity,
          comment: comment,
          studentIds: selectedStudents,
          date: finalDate, // Date object
          grade: isSchoolMode ? 'General' : (filters.grade === 'Todos' ? 'Varios' : filters.grade),
          section: isSchoolMode ? 'General' : (filters.section === 'Todos' ? 'Varios' : filters.section),
          level: isSchoolMode ? 'Institucional' : filters.level,
          tags: [...tags, isSchoolMode ? 'Evento Escolar' : 'Clase'],
          performance: performance,
          period: currentPeriod
        };

        if (!navigator.onLine) {
          await saveOffline(fileToUpload, docData);
        } else {
          await EvidenceService.uploadAndCreate(fileToUpload, docData, session.user.id);
        }
      }
      toast.success("¡Guardado!", { id: loadingToast });
      if (keepData) { setFiles([]); setSelectedStudents([]); }
      else { setActivity(''); setComment(''); setPerformance(''); setFiles([]); setSelectedStudents([]); setTags([]); }
    } catch (error) { toast.error("Error: " + error.message, { id: loadingToast }); } finally { setLoading(false); }
  };

  return {
    captureContext, setCaptureContext,
    activity, setActivity, handleActivityChange, selectActivity,
    comment, setComment,
    tags, toggleTag,
    performance, setPerformance,
    customDate, setCustomDate,
    files, setFiles, handleFilesChange, removeFile,
    loading,
    previewFile, setPreviewFile,
    allActivities, suggestions, setSuggestions, recentActivities,
    keepData, setKeepData,
    selectedStudents, setSelectedStudents,
    filters, handleFilterChange,
    searchTerm, setSearchTerm,
    saveEvidence,
    currentPeriod
  };
}

// src/hooks/useStudents.js
import { useState, useEffect } from 'react';
import { supabase } from '../supabase';
import toast from 'react-hot-toast';
import { StudentService } from '../services/studentService';

export function useStudents() {
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    let subscription = null;

    const fetchStudents = async (userId) => {
        try {
            const { data, error } = await supabase.from('students').select('*').eq('teacher_id', userId);
            if (error) throw error;

             data.sort((a, b) => {
              if (a.grade_name !== b.grade_name) return (a.grade_name || '').localeCompare(b.grade_name || '');
              if (a.section_name !== b.section_name) return (a.section_name || '').localeCompare(b.section_name || '');
              return (Number(a.list_number) || 0) - (Number(b.list_number) || 0);
            });

            const mapped = data.map(s => ({
                id: s.id,
                name: s.name,
                studentId: s.student_id,
                level: s.level_name,
                shift: s.shift_name,
                grade: s.grade_name,
                section: s.section_name,
                listNumber: s.list_number,
                birthDate: s.birth_date,
                photoUrl: s.photo_url
            }));

            setStudents(mapped);
            setLoading(false);
        } catch (e) {
            setError(e);
            setLoading(false);
        }
    };

    const { data: authListener } = supabase.auth.onAuthStateChange((event, session) => {
      if (session?.user) {
         fetchStudents(session.user.id);

         subscription = supabase.channel('students_channel')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'students', filter: `teacher_id=eq.${session.user.id}` }, payload => {
                fetchStudents(session.user.id);
            })
            .subscribe();

      } else {
        setStudents([]);
        setLoading(false);
        if (subscription) supabase.removeChannel(subscription);
      }
    });

    return () => {
        authListener?.subscription.unsubscribe();
        if (subscription) supabase.removeChannel(subscription);
    };
  }, []);

  const addStudent = async (studentData) => {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.user) return;
      try {
          await StudentService.create(studentData, session.user.id, session.user.email);
          toast.success("Alumno agregado");
      } catch (e) {
          toast.error("Error al agregar");
      }
  };

  const updateStudent = async (id, data) => {
     try {
          await StudentService.update(id, data);
          toast.success("Alumno actualizado");
      } catch (e) {
          toast.error("Error al actualizar");
      }
  };

  const deleteStudent = async (id) => {
      if (!confirm("¿Eliminar alumno? Se perderá su asociación a las evidencias.")) return;
       try {
          await StudentService.delete(id);
          toast.success("Alumno eliminado");
      } catch (e) {
          toast.error("Error al eliminar");
      }
  };

  return { students, loading, error, addStudent, updateStudent, deleteStudent };
}

import { useState, useEffect } from 'react';
import { supabase } from '../supabase';
import toast from 'react-hot-toast';

export function useTags() {
    const [availableTags, setAvailableTags] = useState([]);
    const [loadingTags, setLoadingTags] = useState(true);

    useEffect(() => {
        let subscription = null;

        const fetchTags = async (userId) => {
            const { data, error } = await supabase.from('teacher_tags').select('name').eq('teacher_id', userId);
            if (error) {
                console.error(error);
            } else {
                if (data.length === 0) {
                     const defaults = ['Importante', 'Tarea', 'Examen', 'Conducta', 'Participación'].map(t => ({
                         teacher_id: userId,
                         name: t
                     }));
                     await supabase.from('teacher_tags').insert(defaults);
                     setAvailableTags(['Importante', 'Tarea', 'Examen', 'Conducta', 'Participación']);
                } else {
                    setAvailableTags(data.map(d => d.name));
                }
            }
            setLoadingTags(false);
        };

        const { data: authListener } = supabase.auth.onAuthStateChange((event, session) => {
            if (session?.user) {
                fetchTags(session.user.id);
                subscription = supabase.channel('tags_channel')
                    .on('postgres_changes', { event: '*', schema: 'public', table: 'teacher_tags', filter: `teacher_id=eq.${session.user.id}` }, payload => {
                        fetchTags(session.user.id);
                    })
                    .subscribe();
            } else {
                setAvailableTags([]);
                setLoadingTags(false);
                if (subscription) supabase.removeChannel(subscription);
            }
        });

        return () => {
            authListener?.subscription.unsubscribe();
            if (subscription) supabase.removeChannel(subscription);
        };
    }, []);

    const addTag = async (newTag) => {
        if (!newTag.trim()) return;
        const tag = newTag.trim();
        if (availableTags.includes(tag)) return toast.error('La etiqueta ya existe');

        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.user) return;

        try {
            const { error } = await supabase.from('teacher_tags').insert({ teacher_id: session.user.id, name: tag });
            if (error) throw error;
            toast.success('Etiqueta creada');
        } catch (error) {
            console.error("Error adding tag:", error);
            toast.error('Error al crear etiqueta');
        }
    };

    const deleteTag = async (tagToDelete) => {
        if (!confirm(`¿Eliminar etiqueta "${tagToDelete}"?`)) return;
        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.user) return;

        try {
            const { error } = await supabase.from('teacher_tags').delete().eq('teacher_id', session.user.id).eq('name', tagToDelete);
            if (error) throw error;
            toast.success('Etiqueta eliminada');
        } catch (error) {
            console.error("Error deleting tag:", error);
            toast.error('Error al eliminar etiqueta');
        }
    };

    return { availableTags, loadingTags, addTag, deleteTag };
}

import { useState, useEffect } from 'react';
import { useStudents } from '../hooks/useStudents';
import { useTags } from '../hooks/useTags';
import { supabase } from '../supabase';
import { Save, User, Users, Tag, Database, Download, Trash2, Plus, Edit2, Check, X } from 'lucide-react';
import toast from 'react-hot-toast';
import { saveAs } from 'file-saver';

export function Settings() {
    const [activeTab, setActiveTab] = useState('general');
    const { students, addStudent, updateStudent, deleteStudent } = useStudents();
    const { availableTags, addTag, deleteTag } = useTags();

    // General Profile State
    const [profile, setProfile] = useState({ name: '', school: '' });
    const [loadingProfile, setLoadingProfile] = useState(true);

    // Student Edit State
    const [editingStudent, setEditingStudent] = useState(null);
    const [newStudent, setNewStudent] = useState({ name: '', grade: '', section: '', listNumber: '' });

    // Tags State
    const [newTag, setNewTag] = useState('');

    useEffect(() => {
        const fetchProfile = async () => {
             const { data: { session } } = await supabase.auth.getSession();
             if (session?.user) {
                const { data, error } = await supabase.from('teachers').select('*').eq('id', session.user.id).single();
                if (!error && data) {
                    setProfile({ 
                        name: data.full_name || '', 
                        school: data.school_id || '', // we'd need school mapping ideally but string is a placeholder for now
                        currentPeriod: 'P1' // Simplified placeholder 
                    });
                }
             }
             setLoadingProfile(false);
        };
        fetchProfile();
    }, []);

    const saveProfile = async () => {
        try {
            const { data: { session } } = await supabase.auth.getSession();
            if(!session?.user) return;
            // update teachers profile
             await supabase.from('teachers').update({ full_name: profile.name }).eq('id', session.user.id);
            toast.success("Perfil guardado");
        } catch (e) { toast.error("Error al guardar"); }
    };

    const handleAddStudent = async (e) => {
        e.preventDefault();
        if (!newStudent.name) return toast.error("Nombre requerido");
        await addStudent(newStudent);
        setNewStudent({ name: '', grade: '', section: '', listNumber: '' });
    };

    const handleUpdateStudent = async () => {
        if (!editingStudent.name) return;
        await updateStudent(editingStudent.id, {
            name: editingStudent.name,
            grade: editingStudent.grade,
            section: editingStudent.section,
            listNumber: editingStudent.listNumber
        });
        setEditingStudent(null);
    };

    const exportData = async () => {
        const data = {
            profile,
            tags: availableTags,
            students,
            exportedAt: new Date().toISOString()
        };
        const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });
        saveAs(blob, "huella_escolar_backup.json");
        toast.success("Copia de seguridad descargada");
    };

    const tabStyle = (id) => ({
        padding: '10px 15px',
        cursor: 'pointer',
        borderBottom: activeTab === id ? '2px solid var(--accent-color)' : 'none',
        color: activeTab === id ? 'var(--accent-color)' : 'var(--text-secondary)',
        fontWeight: activeTab === id ? 'bold' : 'normal',
        display: 'flex', alignItems: 'center', gap: '5px'
    });

    return (
        <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto', paddingBottom: '80px' }}>
            <h2 style={{ fontSize: '24px', fontWeight: 'bold', marginBottom: '20px', color: 'var(--text-primary)' }}>Configuración</h2>

            <div style={{ display: 'flex', borderBottom: '1px solid var(--border-color)', marginBottom: '20px', overflowX: 'auto' }}>
                <div onClick={() => setActiveTab('general')} style={tabStyle('general')}><User size={18} /> General</div>
                <div onClick={() => setActiveTab('students')} style={tabStyle('students')}><Users size={18} /> Alumnos</div>
                <div onClick={() => setActiveTab('tags')} style={tabStyle('tags')}><Tag size={18} /> Etiquetas</div>
                <div onClick={() => setActiveTab('data')} style={tabStyle('data')}><Database size={18} /> Datos</div>
            </div>

            {/* GENERAL TAB */}
            {activeTab === 'general' && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                    <div>
                        <label style={{ display: 'block', fontSize: '12px', color: 'var(--text-secondary)', marginBottom: '5px' }}>Nombre del Docente</label>
                        <input value={profile.name} onChange={e => setProfile({ ...profile, name: e.target.value })} style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid var(--border-color)', background: 'var(--bg-card)', color: 'var(--text-primary)' }} placeholder="Ej. Prof. María" />
                    </div>
                    <div>
                        <label style={{ display: 'block', fontSize: '12px', color: 'var(--text-secondary)', marginBottom: '5px' }}>Escuela / Centro Educativo</label>
                        <input value={profile.school} onChange={e => setProfile({ ...profile, school: e.target.value })} style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid var(--border-color)', background: 'var(--bg-card)', color: 'var(--text-primary)' }} placeholder="Ej. Escuela Primaria..." />
                    </div>
                    <div>
                        <label style={{ display: 'block', fontSize: '12px', color: 'var(--text-secondary)', marginBottom: '5px' }}>Periodo Académico Activo</label>
                        <select value={profile.currentPeriod || 'P1'} onChange={e => setProfile({ ...profile, currentPeriod: e.target.value })} style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid var(--border-color)', background: 'var(--bg-card)', color: 'var(--text-primary)' }}>
                            <option value="P1">Periodo 1 (P1)</option>
                            <option value="P2">Periodo 2 (P2)</option>
                            <option value="P3">Periodo 3 (P3)</option>
                            <option value="P4">Periodo 4 (P4)</option>
                        </select>
                    </div>
                    <button onClick={saveProfile} style={{ padding: '12px', background: 'var(--accent-color)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', fontWeight: 'bold' }}><Save size={18} /> Guardar Perfil</button>
                </div>
            )}

            {/* STUDENTS TAB */}
            {activeTab === 'students' && (
                <div>
                    <form onSubmit={handleAddStudent} style={{ background: 'var(--bg-card)', padding: '15px', borderRadius: '12px', marginBottom: '20px', border: '1px solid var(--border-color)' }}>
                        <h3 style={{ fontSize: '16px', margin: '0 0 10px 0', color: 'var(--text-primary)' }}>Agregar Alumno</h3>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginBottom: '10px' }}>
                            <input value={newStudent.name} onChange={e => setNewStudent({ ...newStudent, name: e.target.value })} placeholder="Nombre Completo" style={{ gridColumn: 'span 2', padding: '8px', borderRadius: '6px', border: '1px solid var(--border-color)', background: 'var(--bg-primary)', color: 'var(--text-primary)' }} />
                            <input value={newStudent.grade} onChange={e => setNewStudent({ ...newStudent, grade: e.target.value })} placeholder="Grado (ej. 4to)" style={{ padding: '8px', borderRadius: '6px', border: '1px solid var(--border-color)', background: 'var(--bg-primary)', color: 'var(--text-primary)' }} />
                            <input value={newStudent.section} onChange={e => setNewStudent({ ...newStudent, section: e.target.value })} placeholder="Sección (ej. A)" style={{ padding: '8px', borderRadius: '6px', border: '1px solid var(--border-color)', background: 'var(--bg-primary)', color: 'var(--text-primary)' }} />
                        </div>
                        <button type="submit" style={{ width: '100%', padding: '10px', background: 'var(--success-text)', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px' }}><Plus size={16} /> Agregar</button>
                    </form>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                        {students.map(student => (
                            <div key={student.id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '10px', background: 'var(--bg-card)', borderRadius: '8px', border: '1px solid var(--border-color)' }}>
                                {editingStudent?.id === student.id ? (
                                    <div style={{ display: 'flex', gap: '5px', flex: 1 }}>
                                        <input value={editingStudent.name} onChange={e => setEditingStudent({ ...editingStudent, name: e.target.value })} style={{ flex: 2, padding: '5px', borderRadius: '4px', border: '1px solid var(--border-color)' }} />
                                        <input value={editingStudent.grade} onChange={e => setEditingStudent({ ...editingStudent, grade: e.target.value })} style={{ width: '50px', padding: '5px', borderRadius: '4px', border: '1px solid var(--border-color)' }} />
                                        <input value={editingStudent.section} onChange={e => setEditingStudent({ ...editingStudent, section: e.target.value })} style={{ width: '30px', padding: '5px', borderRadius: '4px', border: '1px solid var(--border-color)' }} />
                                        <button onClick={handleUpdateStudent} style={{ background: 'var(--success-text)', color: 'white', border: 'none', borderRadius: '4px', padding: '5px', cursor: 'pointer' }}><Check size={16} /></button>
                                        <button onClick={() => setEditingStudent(null)} style={{ background: 'var(--text-secondary)', color: 'white', border: 'none', borderRadius: '4px', padding: '5px', cursor: 'pointer' }}><X size={16} /></button>
                                    </div>
                                ) : (
                                    <>
                                        <div>
                                            <div style={{ fontWeight: 'bold', color: 'var(--text-primary)' }}>{student.name}</div>
                                            <div style={{ fontSize: '12px', color: 'var(--text-secondary)' }}>{student.grade} {student.section}</div>
                                        </div>
                                        <div style={{ display: 'flex', gap: '5px' }}>
                                            <button onClick={() => setEditingStudent(student)} style={{ padding: '6px', background: 'var(--bg-primary)', border: '1px solid var(--border-color)', borderRadius: '4px', cursor: 'pointer', color: 'var(--text-primary)' }}><Edit2 size={16} /></button>
                                            <button onClick={() => deleteStudent(student.id)} style={{ padding: '6px', background: 'var(--danger-bg)', border: '1px solid var(--danger-text)', borderRadius: '4px', cursor: 'pointer', color: 'var(--danger-text)' }}><Trash2 size={16} /></button>
                                        </div>
                                    </>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* TAGS TAB */}
            {activeTab === 'tags' && (
                <div>
                    <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
                        <input value={newTag} onChange={e => setNewTag(e.target.value)} placeholder="Nueva etiqueta..." style={{ flex: 1, padding: '10px', borderRadius: '8px', border: '1px solid var(--border-color)', background: 'var(--bg-card)', color: 'var(--text-primary)' }} />
                        <button onClick={() => { addTag(newTag); setNewTag(''); }} style={{ padding: '10px 20px', background: 'var(--accent-color)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>Agregar</button>
                    </div>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
                        {availableTags.map(tag => (
                            <div key={tag} style={{ padding: '8px 12px', background: 'var(--bg-card)', border: '1px solid var(--border-color)', borderRadius: '20px', display: 'flex', alignItems: 'center', gap: '8px', color: 'var(--text-primary)' }}>
                                <span>{tag}</span>
                                <button onClick={() => deleteTag(tag)} style={{ background: 'none', border: 'none', color: 'var(--danger-text)', cursor: 'pointer', display: 'flex', alignItems: 'center' }}><X size={14} /></button>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* DATA TAB */}
            {activeTab === 'data' && (
                <div style={{ textAlign: 'center', padding: '40px 20px', background: 'var(--bg-card)', borderRadius: '12px', border: '1px solid var(--border-color)' }}>
                    <Database size={48} color="var(--text-secondary)" style={{ marginBottom: '20px' }} />
                    <h3 style={{ color: 'var(--text-primary)' }}>Copia de Seguridad</h3>
                    <p style={{ color: 'var(--text-secondary)', marginBottom: '20px' }}>Descarga un archivo JSON con toda la información de tus alumnos, etiquetas y perfil. (No incluye las imágenes/videos, solo los enlaces).</p>
                    <button onClick={exportData} style={{ padding: '12px 20px', background: 'var(--success-text)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', display: 'inline-flex', alignItems: 'center', gap: '10px', fontSize: '16px', fontWeight: 'bold' }}><Download size={20} /> Descargar Backup</button>
                </div>
            )}
        </div>
    );
}

// src/services/studentService.js
import { supabase } from '../supabase';

const TABLE_NAME = 'students';

export const StudentService = {

  // Crear nuevo alumno
  create: async (studentData, userId, userEmail) => {
    const dataToSave = {
      teacher_id: userId,
      school_id: studentData.schoolId || null,
      student_id: studentData.studentId || null,
      name: studentData.name,
      level_name: studentData.level,
      shift_name: studentData.shift,
      grade_name: studentData.grade,
      section_name: studentData.section,
      list_number: Number(studentData.listNumber) || 0,
      birth_date: studentData.birthDate || null,
      photo_url: studentData.photoUrl || null
    };

    const { data, error } = await supabase.from(TABLE_NAME).insert(dataToSave).select().single();
    if (error) throw error;
    return data;
  },

  // Actualizar alumno existente
  update: async (id, studentData) => {
    const dataToUpdate = {
      name: studentData.name,
      level_name: studentData.level,
      shift_name: studentData.shift,
      grade_name: studentData.grade,
      section_name: studentData.section,
      list_number: Number(studentData.listNumber) || 0,
      birth_date: studentData.birthDate || null,
      updated_at: new Date().toISOString()
    };
    if (studentData.photoUrl !== undefined) dataToUpdate.photo_url = studentData.photoUrl;

    const { data, error } = await supabase.from(TABLE_NAME).update(dataToUpdate).eq('id', id).select().single();
    if (error) throw error;
    return data;
  },

  // Borrar alumno
  delete: async (id) => {
    const { error } = await supabase.from(TABLE_NAME).delete().eq('id', id);
    if (error) throw error;
    return true;
  },

  // Verificar duplicados (ID Estudiante)
  checkDuplicateId: async (studentId, userId, excludeId = null) => {
    if (!studentId) return false;

    let query = supabase.from(TABLE_NAME).select('id').eq('teacher_id', userId).eq('student_id', studentId);

    const { data, error } = await query;
    if (error) throw error;

    if (data.length > 0 && excludeId) {
      if (data[0].id === excludeId) return false;
    }
    return data.length > 0;
  }
};
